class MinHeap:
    def __init__(self):
        self.data: list = []
    
    def push(self, val: int):
        self.data.append(val)
        self._bubble_up((len(self.data) - 1))
    
    def pop(self) -> int:
        if (notself.data):
            raise IndexError('pop from empty heap')
        root: int = self.data[0]
        last: int = self.data.pop()
        if self.data:
            self.data[0] = last
            self._sink_down(0)
        return root
    
    def _bubble_up(self, i: int):
        while i > 0:
            parent: int = ((i - 1) // 2)
            if self.data[i] < self.data[parent]:
                (self.data[i], self.data[parent]) = (self.data[parent], self.data[i])
                i = parent
            else:
                break
    
    def _sink_down(self, i: int):
        n: int = len(self.data)
        while True:
            smallest: int = i
            left: int = ((2 * i) + 1)
            right: int = ((2 * i) + 2)
            if left < n and self.data[left] < self.data[smallest]:
                smallest = left
            if right < n and self.data[right] < self.data[smallest]:
                smallest = right
            if smallest != i:
                (self.data[i], self.data[smallest]) = (self.data[smallest], self.data[i])
                i = smallest
            else:
                break
    
    def peek(self) -> int:
        return self.data[0]
    
    def __len__(self) -> int:
        return len(self.data)
    

def test_stack():
    print('=== Stack (pointer-linked) ===')
    s = Stack()
    for i in [10, 20, 30, 40, 50]:
        s.push(i)
    print(f"""  Stack: {s.to_list()}""")
    print(f"""  Size:  {len(s)}""")
    print(f"""  Peek:  {s.peek()}""")
    popped: list = []
    while (nots.is_empty()):
        popped.append(s.pop())
    print(f"""  Popped (LIFO): {popped}""")
    print(f"""  Empty: {s.is_empty()}""")

