    print(f"""  Forward:  {dll.forward()}""")
    print(f"""  Backward: {dll.backward()}""")
    print(f"""  Count:    {dll.count}""")
    dll.pop_back()
    dll.pop_back()
    print(f"""  After 2 pops: {dll.forward()}""")

